INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "青空の下で謁見", "ペコリーヌとの出会い", 0, "フリーマーケット会場", 5118061, 2, 2834, 7, 20063115, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "未来の騎空団\nマスコット？", "マホとの出会い", 0, "フリーマーケット会場", 5118062, 2, 2835, 7, 20063115, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "お嬢さまからの\n緊急依頼", "アキノとの出会い", 0, "ランドソル市街地", 5118063, 2, 2837, 7, 20063115, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "黄金色の悩みごと", "ジュンとの出会い", 0, "フリーマーケット会場", 5118064, 2, 4108402, 18, 20063115, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "白熱！　格闘大会！", "カオリとの出会い", 0, "フリーマーケット会場", 5118065, 2, 4107402, 18, 20063115, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "祭り太鼓はオーエドの華", "ニノンとの出会い", 1, "オーエド町", 5118066, 2, 9000227, 16, 20063115, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "人気者は遅れて\nやってくる", "スズナとの出会い", 0, "フリーマーケット会場", 5118067, 3, 2101181, 19, 20063115, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "巫女・ミーツ・魔法少女", "ナナカとの出会い", 0, "ランドソル市街地", 5118068, 3, 4109402, 18, 20063115, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "ネズ耳は二度なくなる", "キャル＆コッコロとの出会い", 0, "フリーマーケット会場", 5118069, 3, 4305402, 18, 20063115, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "この出会いにカンパイ！", "ユカリとの出会い", 0, "ランドソル市街地", 5118070, 3, 4101402, 18, 20063115, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "陰陽アンサンブル", "アオイとの出会い", 0, "ランドソル市街地", 5118071, 3, 4106402, 18, 20063115, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (91002, "運試し十番勝負！", "シノブとの出会い", 1, "フリーマーケット会場", 5118072, 3, 2836, 7, 20063115, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 10118, 8, 1, 40);
INSERT INTO `v1_318f00d34af7d5e1a24ae7fc018b5da77c216034ddc147766b6d61bdc0105935` VALUES (0, "彼女たちの新たな日常", "オープニング", 0, 0, 5118600, 1, 0, 0, 20063115, 0, 10118, 0, 0, 0);
